import React, { useState, useCallback, useRef, useEffect } from 'react'
import {
  View, Text, TextInput, TouchableOpacity, StyleSheet, Alert,
  ScrollView, ActivityIndicator,
} from 'react-native'
import { useSafeAreaInsets } from 'react-native-safe-area-context'
import { scanShelvingReelApi, bindShelvingSlotApi, getShelvesApi, getSlotStatesApi } from '../api'
import type { ShelfResponse, SlotSensorState } from '../types/api'
import { useOperator } from '../hooks/useOperator'
import BarcodeScanner from '../components/BarcodeScanner'
import { CameraIcon } from '../components/Icons'

const Colors = {
  primary: '#0066CC', success: '#00AA55', warning: '#FF9900', danger: '#DD3333',
  info: '#3399CC', card: '#FFFFFF', bg: '#F5F7FA', text: '#1A1A1A', textSecondary: '#666666',
}

// ─────────────────────────────────────────────────────────
// 料盘上架 — 三面板实时传感器驱动界面
//
//  I. 扫描料盘   → 扫码后显示料盘信息
//  II. 储位识别   → 传感器实时检测，放入料架自动识别储位，取走复位
//  III. 保存上架   → I + II 都具备时启用保存按钮
// ─────────────────────────────────────────────────────────

export default function ShelvingScreen() {
  const { operator } = useOperator()
  const insets = useSafeAreaInsets()

  // ──── Panel I: Reel Info ────
  const [barcode, setBarcode] = useState('')
  const [reelId, setReelId] = useState<number | null>(null)
  const [materialCode, setMaterialCode] = useState('')
  const [materialName, setMaterialName] = useState('')
  const [reelQty, setReelQty] = useState(0)
  const [isScanned, setIsScanned] = useState(false)
  const [isAlreadyBound, setIsAlreadyBound] = useState(false)

  // ──── Panel II: Slot Detection ────
  const [shelves, setShelves] = useState<ShelfResponse[]>([])
  const [selectedShelf, setSelectedShelf] = useState<ShelfResponse | null>(null)
  const [detectedSlot, setDetectedSlot] = useState<SlotSensorState | null>(null)
  const [isPolling, setIsPolling] = useState(false)
  const pollingRef = useRef<ReturnType<typeof setInterval> | null>(null)
  const prevStatesRef = useRef<Map<number, boolean>>(new Map())
  // Refs to avoid stale closures in polling callback
  const reelIdRef = useRef<number | null>(null)
  const selectedShelfRef = useRef<ShelfResponse | null>(null)
  const detectedSlotRef = useRef<SlotSensorState | null>(null)

  // ──── Panel III: Save ────
  const [isLoading, setIsLoading] = useState(false)
  const [isSaving, setIsSaving] = useState(false)
  const [resultMsg, setResultMsg] = useState('')
  const [isDone, setIsDone] = useState(false)

  // Keep refs in sync
  useEffect(() => { reelIdRef.current = reelId }, [reelId])
  useEffect(() => { selectedShelfRef.current = selectedShelf }, [selectedShelf])
  useEffect(() => { detectedSlotRef.current = detectedSlot }, [detectedSlot])

  // ──── Load shelves on mount ────
  useEffect(() => { loadShelves() }, [])

  // Cleanup on unmount
  useEffect(() => () => stopPolling(), [])

  const loadShelves = useCallback(async () => {
    try {
      const list = await getShelvesApi()
      setShelves(list.filter(s => s.active === 1))
    } catch { /* ignore */ }
  }, [])

  // ═══════════════════════════════════════════
  //  Panel II: Slot Sensor Polling
  //  (Defined before Panel I handlers to avoid hook ordering issues)
  // ═══════════════════════════════════════════

  const stopPolling = useCallback(() => {
    if (pollingRef.current) {
      clearInterval(pollingRef.current)
      pollingRef.current = null
    }
    setIsPolling(false)
  }, [])

  const startPolling = useCallback((shelfId: number) => {
    stopPolling()
    setIsPolling(true)
    setDetectedSlot(null)
    prevStatesRef.current = new Map()

    pollingRef.current = setInterval(async () => {
      const currentReelId = reelIdRef.current
      if (currentReelId == null) return

      try {
        const stateRes = await getSlotStatesApi(shelfId)
        const currentStates = new Map<number, boolean>()
        for (const slot of stateRes.slots) {
          currentStates.set(slot.slot_id, slot.has_material)
        }

        const prevStates = prevStatesRef.current

        // First poll → just record initial state, no detection yet
        if (prevStates.size === 0) {
          prevStatesRef.current = currentStates
          return
        }

        // Check for state changes: look for newly occupied or vacated slots
        for (const slot of stateRes.slots) {
          const wasOccupied = prevStates.get(slot.slot_id)

          if (wasOccupied === false && slot.has_material) {
            // Slot just became occupied — check it's not already bound to another reel
            if (slot.bound_reel_id == null || slot.bound_reel_id === currentReelId) {
              setDetectedSlot(slot)
              break
            }
          }
        }

        // Check if our detected slot became empty (reel removed)
        const currentDetected = detectedSlotRef.current
        if (currentDetected) {
          const currentOccupied = currentStates.get(currentDetected.slot_id)
          if (currentOccupied === false) {
            // Reel was removed from the slot
            setDetectedSlot(null)
          }
        }

        prevStatesRef.current = currentStates
      } catch {
        // Polling error — keep trying silently
      }
    }, 1500)
  }, [stopPolling])

  // ═══════════════════════════════════════════
  //  Panel I: Scan Reel
  // ═══════════════════════════════════════════

  const handleScanReel = useCallback(async (code?: string) => {
    const scanCode = (code || barcode).trim()
    if (!scanCode) return
    setIsLoading(true)
    setResultMsg('')
    try {
      const res = await scanShelvingReelApi(scanCode)
      setReelId(res.reel_id)
      setMaterialCode(res.material_code)
      setMaterialName(res.material_name || '')
      setReelQty(res.quantity)
      setIsScanned(true)

      if (res.status === 'already_bound') {
        setIsAlreadyBound(true)
        setResultMsg(`该料盘已上架至 ${res.shelf_code || ''}/${res.slot_code || ''}`)
        setIsDone(true)
      } else {
        setIsAlreadyBound(false)
        // Start sensor polling if a shelf is selected
        if (selectedShelfRef.current) {
          startPolling(selectedShelfRef.current.id)
        }
      }
    } catch (e: any) {
      Alert.alert('扫描失败', e?.response?.data?.detail || '请检查条码')
    } finally {
      setIsLoading(false)
    }
  }, [barcode, startPolling])

  const handleCameraScan = useCallback((barcodeValue: string) => {
    setBarcode(barcodeValue)
    setShowScanner(false)
    handleScanReel(barcodeValue)
  }, [handleScanReel])

  // ──── Shelf Selection ────
  const handleSelectShelf = useCallback((shelf: ShelfResponse) => {
    setSelectedShelf(shelf)
    setDetectedSlot(null)
    if (reelIdRef.current != null && !isDone) {
      stopPolling()
      startPolling(shelf.id)
    }
  }, [isDone, startPolling, stopPolling])

  // ═══════════════════════════════════════════
  //  Panel III: Save
  // ═══════════════════════════════════════════

  const handleSave = useCallback(async () => {
    if (reelId == null || detectedSlot == null || selectedShelf == null) return
    setIsSaving(true)
    try {
      const res = await bindShelvingSlotApi({
        reel_id: reelId,
        shelf_id: selectedShelf.id,
        shelf_slot_id: detectedSlot.slot_id,
        operator,
      })
      setResultMsg(`上架成功!\n料架: ${res.shelf_code}\n储位: ${res.slot_code}`)
      setIsDone(true)
      stopPolling()
    } catch (e: any) {
      Alert.alert('上架失败', e?.response?.data?.detail || '请重试')
    } finally {
      setIsSaving(false)
    }
  }, [reelId, detectedSlot, selectedShelf, operator, stopPolling])

  // ──── Reset for next operation ────
  const handleReset = useCallback(() => {
    stopPolling()
    setBarcode('')
    setReelId(null)
    setMaterialCode('')
    setMaterialName('')
    setReelQty(0)
    setIsScanned(false)
    setIsAlreadyBound(false)
    setDetectedSlot(null)
    setResultMsg('')
    setIsDone(false)
    prevStatesRef.current = new Map()
  }, [stopPolling])

  // ──── UI State ────
  const [showScanner, setShowScanner] = useState(false)

  const canSave = isScanned && !isAlreadyBound && detectedSlot != null && !isSaving && !isDone

  // ─────────────────────────────────────────────────────
  //  Render
  // ─────────────────────────────────────────────────────

  return (
    <View style={styles.container}>
      {/* Header */}
      <View style={[styles.header, { paddingTop: insets.top + 8 }]}>
        <Text style={styles.headerTitle}>料盘上架</Text>
        <Text style={styles.headerSub}>扫描料盘 → 放入料架 → 确认上架</Text>
      </View>

      {/* Shelf Selector Bar */}
      <View style={styles.shelfBar}>
        <Text style={styles.shelfBarLabel}>料架:</Text>
        <ScrollView horizontal showsHorizontalScrollIndicator={false} style={styles.shelfBarScroll}>
          {shelves.length === 0 ? (
            <TouchableOpacity style={styles.shelfChip} onPress={loadShelves}>
              <Text style={styles.shelfChipText}>加载</Text>
            </TouchableOpacity>
          ) : (
            shelves.map(s => (
              <TouchableOpacity
                key={s.id}
                style={[styles.shelfChip, selectedShelf?.id === s.id && styles.shelfChipActive]}
                onPress={() => handleSelectShelf(s)}
              >
                <Text style={[styles.shelfChipText, selectedShelf?.id === s.id && styles.shelfChipTextActive]}>
                  {s.code}
                </Text>
              </TouchableOpacity>
            ))
          )}
        </ScrollView>
        {isPolling && (
          <View style={styles.pollingIndicator}>
            <ActivityIndicator size="small" color={Colors.primary} />
          </View>
        )}
      </View>

      <ScrollView style={styles.scrollArea} contentContainerStyle={styles.scrollContent}>
        {/* ════════════════════════════════════════
            Panel I : 扫描料盘
            ════════════════════════════════════════ */}
        <View style={[styles.panel, isScanned && !isAlreadyBound && styles.panelCompleted]}>
          <View style={styles.panelHeader}>
            <View style={styles.panelTitleRow}>
              <View style={[styles.panelBadge, isScanned ? styles.badgeDone : styles.badgePending]}>
                <Text style={styles.badgeText}>I</Text>
              </View>
              <Text style={styles.panelTitle}>扫描料盘</Text>
            </View>
            {isScanned && !isAlreadyBound && (
              <TouchableOpacity onPress={handleReset}>
                <Text style={styles.rerunLink}>重新扫描</Text>
              </TouchableOpacity>
            )}
          </View>

          {!isScanned ? (
            <>
              <Text style={styles.panelHint}>扫描收料后打印的内部标签条码</Text>
              <View style={styles.scanInputRow}>
                <TextInput
                  style={[styles.input, styles.scanInputFlex]}
                  placeholder="扫描料盘条码"
                  value={barcode}
                  onChangeText={setBarcode}
                  autoFocus
                  onSubmitEditing={() => handleScanReel()}
                />
                <TouchableOpacity
                  style={styles.cameraBtn}
                  onPress={() => setShowScanner(true)}
                >
                  <CameraIcon size={22} color="#fff" />
                </TouchableOpacity>
              </View>
              <TouchableOpacity
                style={[styles.button, !barcode.trim() && styles.buttonDisabled]}
                onPress={() => handleScanReel()}
                disabled={!barcode.trim() || isLoading}
              >
                {isLoading ? (
                  <ActivityIndicator color="#fff" />
                ) : (
                  <Text style={styles.buttonText}>识别料盘</Text>
                )}
              </TouchableOpacity>
            </>
          ) : (
            <View style={styles.reelInfoCard}>
              <View style={styles.reelInfoHeader}>
                <Text style={styles.reelIdText}>Reel #{reelId}</Text>
                {!isAlreadyBound && <Text style={styles.reelStatusTag}>待上架</Text>}
              </View>
              <View style={styles.reelInfoRow}>
                <Text style={styles.reelInfoKey}>物料编码</Text>
                <Text style={styles.reelInfoVal}>{materialCode}</Text>
              </View>
              {materialName ? (
                <View style={styles.reelInfoRow}>
                  <Text style={styles.reelInfoKey}>物料名称</Text>
                  <Text style={styles.reelInfoVal}>{materialName}</Text>
                </View>
              ) : null}
              <View style={styles.reelInfoRow}>
                <Text style={styles.reelInfoKey}>数量</Text>
                <Text style={styles.reelInfoVal}>{reelQty}</Text>
              </View>
            </View>
          )}
        </View>

        {/* ════════════════════════════════════════
            Panel II : 储位识别
            ════════════════════════════════════════ */}
        <View style={[styles.panel, detectedSlot != null && styles.panelCompleted]}>
          <View style={styles.panelHeader}>
            <View style={styles.panelTitleRow}>
              <View style={[styles.panelBadge, detectedSlot != null ? styles.badgeDone : styles.badgePending]}>
                <Text style={styles.badgeText}>II</Text>
              </View>
              <Text style={styles.panelTitle}>储位识别</Text>
            </View>
            {detectedSlot != null && (
              <Text style={styles.detectedTag}>已检测</Text>
            )}
          </View>

          {!isScanned ? (
            <View style={styles.placeholderBox}>
              <Text style={styles.placeholderIcon}>①</Text>
              <Text style={styles.placeholderText}>请先扫描料盘</Text>
            </View>
          ) : isAlreadyBound ? (
            <View style={styles.placeholderBox}>
              <Text style={styles.placeholderIcon}>✓</Text>
              <Text style={styles.placeholderText}>料盘已上架，无需重复操作</Text>
            </View>
          ) : selectedShelf == null ? (
            <View style={styles.placeholderBox}>
              <Text style={styles.placeholderIcon}>②</Text>
              <Text style={styles.placeholderText}>请在上方选择目标料架</Text>
            </View>
          ) : detectedSlot != null ? (
            <View style={styles.slotDetectedCard}>
              <View style={styles.slotIconBox}>
                <Text style={styles.slotIconEmoji}>📦</Text>
              </View>
              <View style={styles.slotDetectedInfo}>
                <View style={styles.slotDetectedRow}>
                  <Text style={styles.slotLabel}>料架</Text>
                  <Text style={styles.slotValue}>{selectedShelf.code}</Text>
                </View>
                <View style={styles.slotDetectedRow}>
                  <Text style={styles.slotLabel}>储位</Text>
                  <Text style={[styles.slotValue, styles.slotCodeHighlight]}>
                    {detectedSlot.side}{detectedSlot.slot_on_board}
                  </Text>
                </View>
                {detectedSlot.bound_reel_id != null && (
                  <View style={styles.slotDetectedRow}>
                    <Text style={styles.slotLabel}>状态</Text>
                    <Text style={[styles.slotValue, { color: Colors.success }]}>已自动绑定</Text>
                  </View>
                )}
              </View>
            </View>
          ) : isPolling ? (
            <View style={styles.pollingWaitingBox}>
              <ActivityIndicator size="large" color={Colors.primary} />
              <Text style={styles.pollingWaitingTitle}>等待放入料架...</Text>
              <Text style={styles.pollingWaitingHint}>
                请将料盘放入 {selectedShelf.code} 的空储位
              </Text>
              <Text style={styles.pollingWaitingSub}>传感器检测中，请稍候</Text>
            </View>
          ) : (
            <View style={styles.placeholderBox}>
              <Text style={styles.placeholderIcon}>⟳</Text>
              <Text style={styles.placeholderText}>传感器未启动</Text>
              <TouchableOpacity
                style={styles.retryBtn}
                onPress={() => startPolling(selectedShelf.id)}
              >
                <Text style={styles.retryBtnText}>启动检测</Text>
              </TouchableOpacity>
            </View>
          )}
        </View>

        {/* ════════════════════════════════════════
            Panel III : 保存上架
            ════════════════════════════════════════ */}
        <View style={styles.panel}>
          <View style={styles.panelHeader}>
            <View style={styles.panelTitleRow}>
              <View style={[styles.panelBadge, styles.badgeAction]}>
                <Text style={styles.badgeText}>III</Text>
              </View>
              <Text style={styles.panelTitle}>确认上架</Text>
            </View>
            {isDone && !isAlreadyBound && <Text style={styles.doneTag}>完成</Text>}
          </View>

          {isDone ? (
            <View style={styles.doneBox}>
              <Text style={styles.doneIcon}>
                {isAlreadyBound ? 'ℹ️' : '✅'}
              </Text>
              <Text style={styles.doneTitle}>
                {isAlreadyBound ? '料盘已上架' : '上架完成'}
              </Text>
              <Text style={styles.doneMessage}>{resultMsg}</Text>
              <TouchableOpacity
                style={[styles.button, styles.nextButton]}
                onPress={handleReset}
              >
                <Text style={styles.buttonText}>继续上架</Text>
              </TouchableOpacity>
            </View>
          ) : (
            <>
              <TouchableOpacity
                style={[
                  styles.button,
                  styles.saveButton,
                  !canSave && styles.buttonDisabled,
                ]}
                onPress={handleSave}
                disabled={!canSave || isSaving}
              >
                {isSaving ? (
                  <ActivityIndicator color="#fff" />
                ) : (
                  <Text style={styles.saveButtonText}>
                    {!isScanned && '请先扫描料盘'}
                    {isScanned && isAlreadyBound && '料盘已上架'}
                    {isScanned && !isAlreadyBound && selectedShelf == null && '请选择料架'}
                    {isScanned && !isAlreadyBound && selectedShelf != null && detectedSlot == null && '等待检测储位'}
                    {isScanned && !isAlreadyBound && detectedSlot != null && '保存上架'}
                  </Text>
                )}
              </TouchableOpacity>
              {!isScanned && <Text style={styles.stepHint}>步骤 1/3: 扫描料盘条码</Text>}
              {isScanned && !isAlreadyBound && selectedShelf == null && (
                <Text style={styles.stepHint}>步骤 1.5/3: 选择目标料架</Text>
              )}
              {isScanned && !isAlreadyBound && selectedShelf != null && detectedSlot == null && (
                <Text style={styles.stepHint}>步骤 2/3: 将料盘放入料架空储位</Text>
              )}
              {isScanned && !isAlreadyBound && detectedSlot != null && (
                <Text style={[styles.stepHint, { color: Colors.success }]}>
                  ✓ 步骤 3/3: 点击「保存上架」完成操作
                </Text>
              )}
            </>
          )}
        </View>

        {/* Bottom padding */}
        <View style={{ height: 40 }} />
      </ScrollView>

      {/* Barcode Scanner Modal */}
      <BarcodeScanner
        visible={showScanner}
        onScan={handleCameraScan}
        onClose={() => setShowScanner(false)}
        title="扫码上架"
      />
    </View>
  )
}

